import React from "react";

export default function Wishlist() {
  const hasItems = false;
  return (
    <div className="page-container">
      <h2>Your Wishlist</h2>
      {hasItems ? (
        <p>Here are your wishlist items.</p>
      ) : (
        <p>Your wishlist is empty.</p>
      )}
    </div>
  );
}
